  1130→  const dateDir = dirname(sessionFile.path);
  1131→
  1132→  // 2. projectDir（super-follow 用），從 session_meta 取得 cwd
  1133→  const codexAgent = new CodexAgent({ verbose: options.verbose });
  1134→  const projectInfo = codexAgent.finder.getProjectInfo
  1135→    ? await codexAgent.finder.getProjectInfo(sessionFile.path)
  1136→    : null;
  1137→  const projectDir = projectInfo?.projectDir ?? dateDir;
  1138→
  1139→  // 3. 掃描既有 subagent IDs
  1140→  const existingIds = options.withSubagents
  1141→    ? await extractCodexSubagentIds(sessionFile.path)
  1142→    : [];
  1143→
  1144→  // 4. 建立監控檔案列表
  1145→  const existingSubFiles =
  1146→    options.withSubagents && existingIds.length > 0
  1147→      ? await buildCodexSubagentFiles(dateDir, existingIds)
  1148→      : [];
  1149→
  1150→  const files: WatchedFile[] = [
  1151→    { path: sessionFile.path, label: MAIN_LABEL },
  1152→    ...existingSubFiles.map((f) => {
