  1156→    }),
  1157→  ];
  1158→
  1159→  if (existingIds.length > 0) {
  1160→    log(options.quiet, chalk.gray(`Found ${existingIds.length} subagent(s)`));
  1161→  }
  1162→  log(options.quiet, chalk.gray('---'));
  1163→
  1164→  // 5. Codex parser 無狀態，多 file 共用一個實例
  1165→  const parser = codexAgent.parser;
  1166→
  1167→  // 6. PaneManager 初始化（Phase 2: --pane 支援）
  1168→  let paneManager: PaneManager | null = null;
