  1197→        log(options.quiet, chalk.gray(`[pane] Opening pane for ${agentId}...`));
  1198→        pm.openPane(agentId, subagentPath, description).catch(
  1199→          (err: unknown) => {
  1200→            log(
  1201→              options.quiet,
  1202→              chalk.yellow(`[pane] Failed to open pane: ${err}`)
  1203→            );
  1204→          }
