  1215→          try {
  1216→            if (subPath) {
  1217→              const parts = await readLastCodexAssistantMessage(
  1218→                subPath,
  1219→                parser
  1220→              );
  1221→              const label = makeCodexAgentLabel(agentId);
  1222→              for (const part of parts) {
  1223→                part.sourceLabel = label;
