 75→
 76→export class CodexSubagentDetector {
 77→  private pendingSpawns: Map<string, PendingSpawn> = new Map();
 78→  private registeredAgentPaths: Map<string, string> = new Map();
 79→  private config: CodexSubagentDetectorConfig;
 80→  private stopped = false;
 81→
 82→  constructor(
 83→    _existingAgentIds: string[],
 84→    config: CodexSubagentDetectorConfig
 85→  ) {
 86→    this.config = config;
 87→    // existingAgentIds reserved for future deduplication use
 88→  }
 89→
 90→  /**
 91→   * 預先登錄已存在的 subagent（供 handleSubagentResume 查詢）
 92→   */
 93→  registerExistingAgent(agentId: string, path: string): void {
 94→    this.registeredAgentPaths.set(agentId, path);
 95→  }
 96→
 97→  handleSpawnAgent(callId: string, agentType: string, message: string): void {
 98→    if (!this.config.enabled) return;
 99→
100→    // 防止同一 callId 重複登錄導致舊 timer 洩漏
101→    const existing = this.pendingSpawns.get(callId);
102→    if (existing) clearTimeout(existing.timer);
103→
104→    const timer = setTimeout(() => {
105→      this.pendingSpawns.delete(callId);
106→    }, 60000);
107→
108→    this.pendingSpawns.set(callId, { agentType, message, timer });
109→  }
110→
111→  handleSpawnAgentOutput(
112→    callId: string,
113→    output: { agent_id: string; nickname?: string }
114→  ): void {
115→    if (!this.config.enabled) return;
116→
117→    const pending = this.pendingSpawns.get(callId);
118→    if (!pending) {
119→      this.config.output.debug(`Codex: unknown callId ${callId}, ignoring`);
120→      return;
121→    }
122→
123→    const agentId = output.agent_id;
124→    if (!isValidCodexAgentId(agentId)) {
125→      this.config.output.warn(
126→        `Codex: invalid agent_id format (not UUID): ${agentId}`
127→      );
128→      return;
129→    }
130→
131→    // Fire async, but don't await in sync handler
132→    this._resolveSubagent(callId, pending, agentId).catch((err) => {
133→      this.config.output.error(
134→        `Codex: Failed to resolve subagent ${agentId} - ${err instanceof Error ? err.message : String(err)}`
135→      );
136→    });
137→  }
138→
139→  private async _resolveSubagent(
140→    callId: string,
141→    pending: PendingSpawn,
142→    agentId: string
143→  ): Promise<void> {
144→    const foundPath = await findSubagentFile(
145→      this.config.sessionDateDir,
146→      agentId
147→    );
148→
149→    // Guard：stop() 後捨棄結果，避免向舊 watcher 注入資料
150→    if (this.stopped) return;
151→
152→    if (!foundPath) {
153→      this.config.output.warn(
154→        `Codex subagent file not found after retries: ${agentId}`
155→      );
156→      return;
157→    }
158→
159→    // Cleanup pending
160→    clearTimeout(pending.timer);
161→    this.pendingSpawns.delete(callId);
162→
163→    // 記錄已知 agent（供 handleSubagentResume 查詢路徑）
164→    this.registeredAgentPaths.set(agentId, foundPath);
165→
166→    // Guard：addFile 前再次確認未停止（watcher 是 let 閉包，可能已換新實例）
167→    if (this.stopped) return;
168→
169→    const label = makeCodexAgentLabel(agentId);
170→    await this.config.watcher.addFile({ path: foundPath, label });
171→
172→    // Guard：addFile 是 async，完成後再確認一次，防止 onNewSubagent 對已切換的 session 觸發
173→    if (this.stopped) return;
174→
175→    const description =
176→      pending.agentType && pending.message
177→        ? `${pending.agentType}: ${pending.message.slice(0, 50)}`
178→        : undefined;
179→    this.config.onNewSubagent?.(agentId, foundPath, description);
180→  }
181→
182→  handleSubagentResume(agentId: string): void {
183→    if (!this.config.enabled) return;
184→    if (!isValidCodexAgentId(agentId)) return;
185→
186→    const path = this.registeredAgentPaths.get(agentId);
187→    if (path) {
188→      this.config.onSubagentEnter?.(agentId, path);
189→    }
190→  }
191→
192→  getAgentPath(agentId: string): string | undefined {
193→    return this.registeredAgentPaths.get(agentId);
194→  }
195→
196→  handleSubagentDone(agentId: string): void {
197→    this.config.onSubagentDone?.(agentId);
198→  }
199→
200→  stop(): void {
201→    this.stopped = true;
202→    for (const pending of this.pendingSpawns.values()) {
203→      clearTimeout(pending.timer);
204→    }
205→    this.pendingSpawns.clear();
206→    this.registeredAgentPaths.clear();
207→  }
208→}
