  const SUBAGENT_FILENAME = `rollout-2026-03-07T00-00-01-${SUBAGENT_UUID}.jsonl`;

  beforeEach(async () => {
    tempDir = await mkdtemp(join(tmpdir(), 'codex-resume-test-'));
    output = createMockOutput();
    watcher = createMockWatcher();
    onNewSubagentCalls = [];
    onSubagentEnterCalls = [];
  });

  afterEach(async () => {
