  // ------------------------------------------------------------------
  // handleSubagentResume: known agentId → triggers onSubagentEnter
  // ------------------------------------------------------------------

  test('handleSubagentResume: 已知 agentId → 觸發 onSubagentEnter 帶正確 path', async () => {
