    expect(onSubagentEnterCalls).toHaveLength(1);
    expect(onSubagentEnterCalls[0]!.agentId).toBe(SUBAGENT_UUID);
    expect(onSubagentEnterCalls[0]!.path).toBe(subagentFile);
