  // ------------------------------------------------------------------
  // getAgentPath
  // ------------------------------------------------------------------

  test('getAgentPath: 已知 agentId → 回傳正確路徑', async () => {
    const subagentFile = join(tempDir, SUBAGENT_FILENAME);
