  // ------------------------------------------------------------------
  // handleSpawnAgentOutput: 已 registerExistingAgent 的 agentId → 跳過 resolve
  // ------------------------------------------------------------------

  test('handleSpawnAgentOutput: 已 registerExistingAgent → 不觸發 onNewSubagent', async () => {
    const subagentFile = join(tempDir, SUBAGENT_FILENAME);
